import { useState, useEffect } from "react";

const GREEN = "#43B02A";
const DARK = "#1C3A2A";
const BLUE = "#0A84FF";
const ORANGE = "#E07B39";
const GRAY_BG = "#f5f5f2";

/* eslint-disable */
const LOGOS = {"satellite":"data:image/jpeg;base64,","splash":"data:image/jpeg;base64,","aldi":"data:image/png;base64,","aldi":"data:image/png;base64,","costco":"data:image/jpeg;base64,","eataly":"data:image/jpeg;base64,","stopnshop":"data:image/jpeg;base64,","target":"data:image/jpeg;base64,","wegmans":"data:image/jpeg;base64,","starmarket":"data:image/jpeg;base64,","dollartree":"data:image/jpeg;base64,"};

function StatusBar({ dark }) {
  return (
    <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "6px 20px 4px", background: dark ? "transparent" : "#fff" }}>
      <span style={{ fontSize: 14, fontWeight: 600, color: dark ? "#fff" : "#000", fontVariantNumeric: "tabular-nums" }}>9:41</span>
      <div style={{ display: "flex", gap: 5, alignItems: "center" }}>
        <svg width="16" height="12" viewBox="0 0 16 12"><rect x="0" y="4" width="3" height="8" rx="0.5" fill={dark?"#fff":"#000"} opacity="0.3"/><rect x="4.5" y="3" width="3" height="9" rx="0.5" fill={dark?"#fff":"#000"} opacity="0.5"/><rect x="9" y="1.5" width="3" height="10.5" rx="0.5" fill={dark?"#fff":"#000"} opacity="0.7"/><rect x="13.5" y="0" width="3" height="12" rx="0.5" fill={dark?"#fff":"#000"}/></svg>
        <svg width="16" height="12" viewBox="0 0 16 12"><path d="M8 1C4.5 1 1.5 2.5 0 5l2.5 0C3.3 3.5 5.5 2.5 8 2.5S12.7 3.5 13.5 5L16 5C14.5 2.5 11.5 1 8 1z" fill={dark?"#fff":"#000"} opacity="0.35"/><path d="M8 4.5C6 4.5 4.3 5.3 3.5 6.5L6 6.5C6.4 5.9 7.1 5.5 8 5.5s1.6.4 2 1L12.5 6.5C11.7 5.3 10 4.5 8 4.5z" fill={dark?"#fff":"#000"} opacity="0.65"/><circle cx="8" cy="9.5" r="2" fill={dark?"#fff":"#000"}/></svg>
        <div style={{ width: 24, height: 11, border: `1.2px solid ${dark?"rgba(255,255,255,0.35)":"rgba(0,0,0,0.3)"}`, borderRadius: 3, padding: 1.2, position: "relative" }}>
          <div style={{ width: "75%", height: "100%", background: dark ? "#30D158" : "#000", borderRadius: 1.5 }} />
          <div style={{ position: "absolute", right: -4, top: 3, width: 2, height: 5, background: dark?"rgba(255,255,255,0.3)":"rgba(0,0,0,0.25)", borderRadius: "0 1px 1px 0" }} />
        </div>
      </div>
    </div>
  );
}

function InstacartSplash({ onDone }) {
  useEffect(() => { const t = setTimeout(onDone, 1000); return () => clearTimeout(t); }, []);
  return (
    <div style={{ minHeight: 640, position: "relative", overflow: "hidden" }}>
      <img src={LOGOS.splash} alt="Instacart" style={{ width: "100%", height: 640, objectFit: "cover" }} />
    </div>
  );
}

