export default function App() {
  const [screen, setScreen] = useState("insta_splash");
  const [mode, setMode] = useState("drone");

  const screenMap = {
    insta_splash: "Launch",
    home: "Home",
    splash: "ALDI splash",
    store: "ALDI store",
    address: "Address",
    ...(mode === "drone" ? { spot: "Drop spot" } : {}),
    checkout: "Checkout",
    ...(mode === "robot" ? { robotcode: "Unlock code" } : {}),
    tracking: "Tracking"
  };

  const phone = (content) => (
    <div style={{ width: 320, height: 640, borderRadius: 32, border: "3px solid #d4d4d0", overflow: "hidden", boxShadow: "0 8px 40px rgba(0,0,0,0.1)", background: "#fff" }}>
      <div style={{ height: "100%", overflowY: "auto", overflowX: "hidden", WebkitOverflowScrolling: "touch" }}>
        {content}
      </div>
    </div>
  );

  const handleCheckout = (cartMode) => {
    setMode(cartMode);
    setScreen("address");
  };

  const handleAddressSelect = (m) => {
    setMode(m);
    if (m === "drone") {
      setScreen("spot");
    } else {
      setScreen("checkout");
    }
  };

  const handlePlaceOrder = () => {
    if (mode === "robot") {
      setScreen("robotcode");
    } else {
      setScreen("tracking");
    }
  };

  return (
    <div style={{ fontFamily: "var(--font-sans)", display: "flex", flexDirection: "column", alignItems: "center", gap: 10, padding: "6px 0" }}>
      <div style={{ display: "flex", gap: 5, flexWrap: "wrap", justifyContent: "center" }}>
        {Object.entries(screenMap).map(([k, v]) => (
          <div key={k} onClick={() => setScreen(k)} style={{ padding: "5px 12px", borderRadius: 16, fontSize: 11, fontWeight: screen === k ? 600 : 400, cursor: "pointer", background: screen === k ? GREEN : "var(--color-background-secondary)", color: screen === k ? "#fff" : "var(--color-text-secondary)", border: `0.5px solid ${screen === k ? GREEN : "var(--color-border-tertiary)"}`, transition: "all 0.15s" }}>
            {v}
          </div>
        ))}
      </div>

      {phone(
        screen === "insta_splash" ? <InstacartSplash onDone={() => setScreen("home")} /> :
        screen === "home" ? <HomeScreen onTapAldi={() => setScreen("splash")} /> :
        screen === "splash" ? <SplashScreen onDone={() => setScreen("store")} /> :
        screen === "store" ? <AldiStore onCheckout={handleCheckout} onBack={() => setScreen("home")} /> :
        screen === "address" ? <AddressScreen mode={mode} onSelect={handleAddressSelect} onBack={() => setScreen("store")} /> :
        screen === "spot" ? <DeliverySpotScreen mode={mode} onContinue={() => setScreen("checkout")} onBack={() => setScreen("address")} /> :
        screen === "checkout" ? <CheckoutScreen mode={mode} onPlaceOrder={handlePlaceOrder} onBack={() => setScreen(mode === "drone" ? "spot" : "address")} /> :
        screen === "robotcode" ? <RobotCodeScreen onContinue={() => setScreen("tracking")} onBack={() => setScreen("checkout")} /> :
        <TrackingScreen mode={mode} onBack={() => setScreen("home")} />
      )}

      <div style={{ fontSize: 11, color: "var(--color-text-tertiary)", textAlign: "center", maxWidth: 300 }}>
        {screen === "insta_splash" && "Instacart app launching..."}
        {screen === "home" && "Tap ALDI (with 🛩 AUTO badge) to start"}
        {screen === "splash" && "Auto-advances in 1s..."}
        {screen === "store" && "Add items — eligibility bar updates live (green=drone, blue=robot, orange=shopper)"}
        {screen === "address" && `Showing ${mode}-eligible address only`}
        {screen === "spot" && "Tap the pulsing blue pin to select drop spot"}
        {screen === "checkout" && "Tap 'Place order'"}
        {screen === "robotcode" && "Your unlock code — use it when the robot arrives"}
        {screen === "tracking" && `Live ${mode} tracking`}
      </div>
    </div>
  );
}
